WebLink.url:
{!REQUIRESCRIPT("/soap/ajax/33.0/connection.js")}



if("{!$Profile.Name}" == 'JS Recruiter - Hybrid')
{
alert('Permission restricted to Payroll Department.');
}
else
{
try{

var conrecord = new sforce.SObject("Contact");

conrecord.Id = "{!Contact.Id}";
conrecord.IP_EmergencyPull__c = true;
conrecord.IP_Pass2ndTierToTempest__c = true;

var result = sforce.connection.update([conrecord ]);

if(result[0].success === "true"){
alert(
"Records Flagged"
);
location.reload(true);
}
else{
alert(
"An Error has Occurred. Error: " +
result[0].errors.message
);
}
}
catch(e){
alert(
"An unexpected Error has Occurred. Error: " +
e
);
}
}
